# Training 2 P1 cells: {(0,5),(4,6),(5,2),(5,4),(5,5),(6,6),(7,5),(9,2),(9,5)}
# Need to find which 4 cells form a rotation of the base shape.
# P1-only cells: {(4,6),(5,5),(6,6)}
# These must be part of the shape. Need 1 more from shared cells.
# Shared cells: {(0,5),(5,2),(5,4),(7,5),(9,2),(9,5)}

# Let's try each shared cell + the 3 P1-only cells:
from itertools import combinations

p1_only = [(4,6),(5,5),(6,6)]
shared = [(0,5),(5,2),(5,4),(7,5),(9,2),(9,5)]

rotations = [
    frozenset([(0, 0), (1, 1), (1, 2), (2, 0)]),   # 0°
    frozenset([(0, 0), (0, 2), (1, 1), (2, 1)]),   # 90°
    frozenset([(0, 2), (1, 0), (1, 1), (2, 2)]),   # 180°
    frozenset([(0, 1), (1, 1), (2, 0), (2, 2)]),   # 270°
]

def normalize(cells):
    cells = list(cells)
    mr = min(r for r,c in cells)
    mc = min(c for r,c in cells)
    return frozenset((r-mr, c-mc) for r,c in cells)

for sc in shared:
    candidate = p1_only + [sc]
    nc = normalize(candidate)
    for ri, rot in enumerate(rotations):
        if nc == rot:
            print(f"Match! Shared cell {sc}, rotation {ri*90}°, candidate: {sorted(candidate)}")

# Also check if maybe 2 P1-only + 2 shared:
for sc1, sc2 in combinations(shared, 2):
    for p1c in p1_only:
        remaining_p1 = [x for x in p1_only if x != p1c]
        candidate = remaining_p1 + [sc1, sc2]
        nc = normalize(candidate)
        for ri, rot in enumerate(rotations):
            if nc == rot:
                print(f"Match2! P1-only excluded: {p1c}, shared {sc1},{sc2}, rot {ri*90}°")

